1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	const CAP_MULTIPLIER = 2;
31	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
32	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
33	
34	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
35	type QuoteStep = { op: "quote"; items: Item[] };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	const sum = (numbers: number[]): number =>
44	  numbers.reduce((total, n) => total + n, 0);
45	
46	// Gold pieces are whole units. Premiums round up (customer pays slightly more);
47	// payouts round down (insurer pays slightly less) — the asymmetry favors the office.
48	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
49	const roundDownToWholeGold = (amount: number): number => Math.floor(amount);
50	
51	const policyInsuranceSum = (items: Item[]): number =>
52	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
53	
54	const isHighEnchantmentForReimbursement = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
56	
57	const effectiveDamage = (item: Item, damageAmount: number): number =>
58	  isHighEnchantmentForReimbursement(item)
59	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
60	    : damageAmount;
61	
62	const findPolicyItem = (policyItems: Item[], itemType: string): Item => {
63	  const found = policyItems.find((item) => item.type === itemType);
64	  if (!found) throw new Error(`damage references item type '${itemType}' not in policy`);
65	  return found;
66	};
67	
68	const damagePayout = (policyItems: Item[], damage: Damage): number =>
69	  effectiveDamage(findPolicyItem(policyItems, damage.itemType), damage.amount) - DEDUCTIBLE;
70	
71	type Policy = { items: Item[]; remainingCap: number };
72	
73	const newPolicy = (items: Item[]): Policy => ({
74	  items,
75	  remainingCap: CAP_MULTIPLIER * policyInsuranceSum(items),
76	});
77	
78	const claimResult = (policy: Policy, step: ClaimStep) => {
79	  const negative = step.incident.damages.find((damage) => damage.amount < 0);
80	  if (negative) throw new Error(`damage amount must be non-negative: ${negative.amount}`);
81	  const computedPayout = sum(step.incident.damages.map((damage) => damagePayout(policy.items, damage)));
82	  const payout = roundDownToWholeGold(Math.min(computedPayout, policy.remainingCap));
83	  return { payout, remainingCap: policy.remainingCap - payout };
84	};
85	
86	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
87	
88	const isBlockOfThreeAlike = (items: Item[]): boolean =>
89	  items.length === 3 && items.every((item) => item.type === items[0].type);
90	
91	const groupByType = (items: Item[]): Item[][] => {
92	  const groups: Record<string, Item[]> = {};
93	  for (const item of items) {
94	    (groups[item.type] ||= []).push(item);
95	  }
96	  return Object.values(groups);
97	};
98	
99	const groupBasePremium = (group: Item[]): number =>
100	  isBlockOfThreeAlike(group)
101	    ? BLOCK_OF_THREE_BASE_PREMIUM
102	    : sum(group.map(itemBasePremium));
103	
104	const itemsBasePremium = (items: Item[]): number =>
105	  sum(groupByType(items).map(groupBasePremium));
106	
107	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
108	  applies ? amount * rate : 0;
109	
110	const cursedSurcharge = (item: Item): number =>
111	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
112	
113	const highEnchantmentSurcharge = (item: Item): number =>
114	  rateIfApplies(
115	    itemBasePremium(item),
116	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
117	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
118	  );
119	
120	const itemSurchargesTotal = (items: Item[]): number =>
121	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
122	
123	const firstInsuranceSurcharge = (basePremium: number): number =>
124	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
125	
126	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
127	  rateIfApplies(
128	    basePremium,
129	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
130	    LOYALTY_DISCOUNT_RATE,
131	  );
132	
133	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
134	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
135	
136	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
137	  const policyBase = itemsBasePremium(items);
138	  return roundUpToWholeGold(
139	    policyBase +
140	      itemSurchargesTotal(items) +
141	      firstInsuranceSurcharge(policyBase) -
142	      loyaltyDiscount(policyBase, customer) -
143	      followupDiscount(policyBase, quoteIndex) +
144	      PROCESSING_FEE,
145	  );
146	};
147	
148	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUMS));
149	
150	const validateItemTypes = (items: Item[]): void => {
151	  const unknown = items.find((item) => !KNOWN_ITEM_TYPES.has(item.type));
152	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
153	};
154	
155	export const runScenario = (input: Scenario): unknown => {
156	  const results: unknown[] = [];
157	  const policies: Policy[] = [];
158	  for (const step of input.steps) {
159	    if (step.op === "quote") {
160	      validateItemTypes(step.items);
161	      const premium = quotePremiumFor(step.items, input.customer, policies.length);
162	      results.push({ premium });
163	      policies.push(newPolicy(step.items));
164	    } else {
165	      const result = claimResult(policies[step.policy], step);
166	      policies[step.policy].remainingCap = result.remainingCap;
167	      results.push(result);
168	    }
169	  }
170	  return { results };
171	};
